-- Create table for Steadfast consignment data
CREATE TABLE IF NOT EXISTS steadfast_consignments (
  tracking_code    TEXT PRIMARY KEY,
  wc_order_id      INTEGER,
  cod_amount       INTEGER NOT NULL DEFAULT 0,
  shipping_charge  INTEGER NOT NULL DEFAULT 0,
  cod_fee          NUMERIC(10,2) NOT NULL DEFAULT 0,
  delivery_status  TEXT,
  booked_at        TIMESTAMPTZ,
  recipient_name   TEXT,
  recipient_phone  TEXT
);

CREATE INDEX IF NOT EXISTS idx_sf_wc_order ON steadfast_consignments(wc_order_id);

-- Insert consignment data (ON CONFLICT updates existing rows)
ON CONFLICT (tracking_code) DO UPDATE SET
  wc_order_id     = EXCLUDED.wc_order_id,
  cod_amount      = EXCLUDED.cod_amount,
  shipping_charge = EXCLUDED.shipping_charge,
  cod_fee         = EXCLUDED.cod_fee,
  delivery_status = EXCLUDED.delivery_status,
  booked_at       = EXCLUDED.booked_at,
  recipient_name  = EXCLUDED.recipient_name,
  recipient_phone = EXCLUDED.recipient_phone;

SELECT COUNT(*) AS rows_inserted FROM steadfast_consignments;